// OrganizationServiceServer is the server API for OrganizationService service.
// All implementations must embed UnimplementedOrganizationServiceServer
// for forward compatibility.
type OrganizationServiceServer interface {
	// CreateOrganization creates a new organization
	CreateOrganization(context.Context, *CreateOrganizationRequest) (*CreateOrganizationResponse, error)
	// GetOrganization returns organization by ID
	GetOrganization(context.Context, *GetOrganizationRequest) (*GetOrganizationResponse, error)
	// UpdateOrganization updates organization
	UpdateOrganization(context.Context, *UpdateOrganizationRequest) (*UpdateOrganizationResponse, error)
	// DeleteOrganization deletes organization (only owner can delete)
	DeleteOrganization(context.Context, *DeleteOrganizationRequest) (*DeleteOrganizationResponse, error)
	// GetMyOrganizations returns organizations where current user is a member
	GetMyOrganizations(context.Context, *GetMyOrganizationsRequest) (*GetMyOrganizationsResponse, error)
	// UpsertByLegacyID upserts organization by legacy_id (for sync service)
	UpsertByLegacyID(context.Context, *UpsertByLegacyIDRequest) (*UpsertByLegacyIDResponse, error)
	// Categories - for matching with requests
	SetCategories(context.Context, *SetCategoriesRequest) (*SetCategoriesResponse, error)
	GetCategories(context.Context, *GetCategoriesRequest) (*GetCategoriesResponse, error)
	// Members
	AddMember(context.Context, *AddMemberRequest) (*AddMemberResponse, error)
	FireMember(context.Context, *FireMemberRequest) (*FireMemberResponse, error)
	UpdateMemberRole(context.Context, *UpdateMemberRoleRequest) (*UpdateMemberRoleResponse, error)
	GetMembers(context.Context, *GetMembersRequest) (*GetMembersResponse, error)
	GetMember(context.Context, *GetMemberRequest) (*GetMemberResponse, error)
	// Invite codes
	CreateInviteCode(context.Context, *CreateInviteCodeRequest) (*CreateInviteCodeResponse, error)
	UseInviteCode(context.Context, *UseInviteCodeRequest) (*UseInviteCodeResponse, error)
	GetInviteCodes(context.Context, *GetInviteCodesRequest) (*GetInviteCodesResponse, error)
	DeactivateInviteCode(context.Context, *DeactivateInviteCodeRequest) (*DeactivateInviteCodeResponse, error)
	// Permissions
	CheckPermission(context.Context, *CheckPermissionRequest) (*CheckPermissionResponse, error)
	GetRoles(context.Context, *GetRolesRequest) (*GetRolesResponse, error)
	// RBAC role management (DB-driven)
	CreateRole(context.Context, *CreateRoleRequest) (*CreateRoleResponse, error)
	UpdateRoleInfo(context.Context, *UpdateRoleInfoRequest) (*UpdateRoleInfoResponse, error)
	DeleteRole(context.Context, *DeleteRoleRequest) (*DeleteRoleResponse, error)
	SetRolePermissions(context.Context, *SetRolePermissionsRequest) (*SetRolePermissionsResponse, error)
	// Per-member permission overrides
	SetMemberPermissionOverride(context.Context, *SetMemberPermissionOverrideRequest) (*SetMemberPermissionOverrideResponse, error)
	RemoveMemberPermissionOverride(context.Context, *RemoveMemberPermissionOverrideRequest) (*RemoveMemberPermissionOverrideResponse, error)
	GetMemberPermissionOverrides(context.Context, *GetMemberPermissionOverridesRequest) (*GetMemberPermissionOverridesResponse, error)
	// Organization profiles (type-specific settings)
	GetOrgProfile(context.Context, *GetOrgProfileRequest) (*GetOrgProfileResponse, error)
	UpdateOrgProfile(context.Context, *UpdateOrgProfileRequest) (*UpdateOrgProfileResponse, error)
	// Subscription info (for payment service)
	GetOrganizationSubscriptionInfo(context.Context, *GetOrgSubscriptionInfoRequest) (*GetOrgSubscriptionInfoResponse, error)
	// ListUserOrganizations returns orgs where user_id is an active member,
	// including the caller's role and whether the org has an active subscription.
	// Used by auth service (SelectOrg flow) and partner onboarding UI.
	ListUserOrganizations(context.Context, *ListUserOrganizationsRequest) (*ListUserOrganizationsResponse, error)
	// CreateDraftOrganization creates an org with status='trial' (minimal fields).
	CreateDraftOrganization(context.Context, *CreateDraftOrganizationRequest) (*CreateDraftOrganizationResponse, error)
	// UpdateOrganizationInfo performs a partial update of legal/contact fields.
	UpdateOrganizationInfo(context.Context, *UpdateOrganizationInfoRequest) (*UpdateOrganizationInfoResponse, error)
	// RequestActivation transitions org status from trial -> pending_docs.
	RequestActivation(context.Context, *RequestActivationRequest) (*RequestActivationResponse, error)
	// SearchOrganizations is the Postgres-backed marketplace catalog that replaces
	// the Elasticsearch-backed services.search.v1.SearchOrganizations. It wraps the
	// org-service domain method FilterCandidates (model.CandidateFilter ->
	// []model.CandidateResult), the shared filter+relevance-rank query that serves
	// both the client catalog and matching-candidate selection. The request shape
	// mirrors services.search.v1.SearchOrganizationsRequest so BFF mapping stays
	// trivial during the ES cutover.
	SearchOrganizations(context.Context, *SearchOrganizationsRequest) (*SearchOrganizationsResponse, error)
	// SetOrganizationMarketplaceFields lets platform admins/moderators edit the
	// marketplace ranking flags (is_reviewed, is_dealer, expert_for_carmake_ids,
	// expert_for_category_ids) on an organization. Each field is optional —
	// omitted means "keep current value". After write, an org.organization.updated
	// event is published so the search index picks up the change.
	SetOrganizationMarketplaceFields(context.Context, *SetOrganizationMarketplaceFieldsRequest) (*SetOrganizationMarketplaceFieldsResponse, error)
	// Deprecated: Do not use.
	// Platform roles (CTOgram employee roles)
	// Deprecated: Use UserService.SetPlatformRoles instead.
	SetPlatformRole(context.Context, *SetPlatformRoleRequest) (*SetPlatformRoleResponse, error)
	// Deprecated: Do not use.
	// Deprecated: Use UserService.GetPlatformRoles instead.
	GetPlatformRole(context.Context, *GetPlatformRoleRequest) (*GetPlatformRoleResponse, error)
	// Deprecated: Do not use.
	// Deprecated: Use UserService.SetPlatformOrgAccess instead.
	SetPlatformOrgAccess(context.Context, *SetPlatformOrgAccessRequest) (*SetPlatformOrgAccessResponse, error)
	// Deprecated: Do not use.
	// Deprecated: Use UserService.GetPlatformOrgAccess instead.
	GetPlatformOrgAccess(context.Context, *GetPlatformOrgAccessRequest) (*GetPlatformOrgAccessResponse, error)
	// Deprecated: Do not use.
	// Deprecated: Use UserService.CheckPlatformRole instead.
	CheckPlatformRole(context.Context, *CheckPlatformRoleRequest) (*CheckPlatformRoleResponse, error)
	mustEmbedUnimplementedOrganizationServiceServer()
}

